// mm/src/api/downloadDocuments.js
import axios from 'axios';
import { withAuthRetry } from './refresh';
import { getAccessToken } from '../utils/auth';

const DEFAULT_API_BASE = 'https://manuscriptmagic.fowkes.xyz/services';
const API_BASE = process.env.REACT_APP_API_BASE_URL || DEFAULT_API_BASE;

/**
 * If backend sends Content-Disposition: attachment; filename="something.pdf"
 * we’ll honor it when filename isn't passed.
 */
function getFilenameFromContentDisposition(cd) {
  if (!cd) return '';
  // Supports: filename="x.pdf" or filename=x.pdf
  const m = /filename\*?=(?:UTF-8''|")?([^;"\n]+)"?/i.exec(cd);
  if (!m?.[1]) return '';
  try {
    return decodeURIComponent(m[1]);
  } catch {
    return m[1];
  }
}

function getExtFromMime(mime) {
  const t = String(mime || '').toLowerCase();
  if (t.includes('application/pdf')) return 'pdf';
  if (t.includes('application/vnd.openxmlformats-officedocument.wordprocessingml.document')) return 'docx';
  if (t.includes('application/msword')) return 'doc';
  if (t.includes('text/plain')) return 'txt';
  if (t.includes('text/markdown')) return 'md';
  if (t.includes('application/zip')) return 'zip';
  return ''; // unknown
}

function ensureExtension(name, ext) {
  if (!name) return ext ? `document.${ext}` : 'document';
  if (!ext) return name;
  const hasExt = /\.[a-z0-9]+$/i.test(name);
  if (hasExt) return name;
  return `${name}.${ext}`;
}

async function blobToText(blob) {
  try {
    return await blob.text();
  } catch {
    return '';
  }
}

/**
 * downloadDocument.php
 * requires: Authorization Bearer <token>
 * body: { documentId }
 * returns: blob (pdf/docx/etc)
 */
export async function downloadDocument(documentId) {
  if (!documentId) throw new Error('documentId is required');

  // DEV MOCK
  if (!process.env.REACT_APP_API_BASE_URL) {
    const blob = new Blob([`Mock file for ${documentId}`], { type: 'application/pdf' });
    return {
      data: blob,
      headers: { 'content-type': 'application/pdf', 'content-disposition': 'attachment; filename="mock.pdf"' },
      status: 200,
    };
  }

  const url = `${API_BASE}/downloadDocument.php`;

  return withAuthRetry(async () => {
    const accessToken = await getAccessToken();
    if (!accessToken) throw new Error('Missing access token');

    console.log('⬇️ downloadDocument request:', { url, documentId });

    const resp = await axios.post(
      url,
      { documentId },
      {
        responseType: 'blob',
        headers: {
          'Content-Type': 'application/json',
          Authorization: `Bearer ${accessToken}`,
          Accept: 'application/octet-stream',
        },
      }
    );

    // Sometimes PHP returns JSON errors even with 200; detect by content-type
    const ct = resp?.headers?.['content-type'] || '';
    const isJsonLike = String(ct).toLowerCase().includes('application/json');

    if (isJsonLike) {
      const text = await blobToText(resp.data);
      let msg = 'Download failed';
      try {
        const parsed = JSON.parse(text);
        msg = parsed?.message || parsed?.error || msg;
      } catch {
        msg = text || msg;
      }
      throw new Error(msg);
    }

    console.log('✅ downloadDocument response:', {
      status: resp.status,
      contentType: resp?.headers?.['content-type'],
      contentDisposition: resp?.headers?.['content-disposition'],
      size: resp?.data?.size,
    });

    return resp;
  });
}

/**
 * Saves blob to disk with best filename.
 * - If server returns PDF -> saved as .pdf
 * - If server returns docx -> saved as .docx, etc.
 *
 * IMPORTANT: We cannot convert DOCX -> PDF here without a conversion library/service.
 * If you must always get a PDF, the backend must generate and return a PDF.
 */
export async function downloadAndSaveDocuments(documentId, preferredName = '') {
  const resp = await downloadDocument(documentId);

  const contentType = resp?.headers?.['content-type'] || 'application/octet-stream';
  const contentDisposition = resp?.headers?.['content-disposition'] || '';

  // Use server filename if you didn’t pass one
  const serverName = getFilenameFromContentDisposition(contentDisposition);

  // Derive extension from MIME
  const ext = getExtFromMime(contentType);

  // Choose filename priority: preferredName > serverName > fallback
  const baseName = (preferredName || serverName || `document_${documentId}`).trim();
  const finalName = ensureExtension(baseName, ext);

  // Re-wrap to ensure type is set (helps some browsers)
  const blob = new Blob([resp.data], { type: contentType });

  const url = window.URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = finalName;
  document.body.appendChild(a);
  a.click();
  a.remove();
  window.URL.revokeObjectURL(url);

  console.log('✅ Download saved:', { documentId, filename: finalName, contentType, size: blob.size });
}
